-- SIMPLE AUTO-FILL: Update subjects.branch_id using classes table\n-- This is the quickest way to auto-fill branch_id\n\n-- Step 1: Check current state\nSELECT 'Subjects without branch_id:' as status;\nSELECT COUNT(*) as count FROM subjects WHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 2: Preview the update (see what will be changed)\nSELECT 'Preview - subjects that will get branch_id from classes:' as preview;\nSELECT \n    s.subject_code,\n    s.subject,\n    s.class_code,\n    s.branch_id as current_branch_id,\n    c.branch_id as new_branch_id,\n    c.class_name\nFROM subjects s\nINNER JOIN classes c ON s.class_code = c.class_code AND s.school_id = c.school_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '')\nAND c.status = 'Active'\nLIMIT 10;\n\n-- Step 3: AUTO-FILL branch_id (THE MAIN UPDATE)\nUPDATE subjects s\nINNER JOIN classes c ON s.class_code = c.class_code AND s.school_id = c.school_id\nSET s.branch_id = c.branch_id\nWHERE (s.branch_id IS NULL OR s.branch_id = '')\nAND c.status = 'Active';\n\n-- Step 4: Check results\nSELECT 'After auto-fill - subjects still without branch_id:' as result;\nSELECT COUNT(*) as remaining_count FROM subjects WHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 5: Show success message\nSELECT \n    CASE \n        WHEN COUNT(*) = 0 THEN '🎉 SUCCESS: All subjects now have branch_id!'\n        ELSE CONCAT('⚠️ ', COUNT(*), ' subjects still need manual assignment')\n    END as final_status\nFROM subjects \nWHERE branch_id IS NULL OR branch_id = '';\n\n-- Step 6: Show distribution\nSELECT 'Final distribution:' as info;\nSELECT \n    school_id,\n    branch_id,\n    COUNT(*) as subject_count\nFROM subjects \nWHERE branch_id IS NOT NULL AND branch_id != ''\nGROUP BY school_id, branch_id\nORDER BY school_id, branch_id;\n"